SELECT strain_name, region 
FROM strains 
WHERE strain_id = 0;

SELECT r.region_name, r.population
FROM regions r
WHERE r.region_name IN (
    SELECT DISTINCT s.region
    FROM strains s
);

SELECT strain_detail_id, age_score 
FROM strain_details 
WHERE age_score = (SELECT MIN(age_score) FROM strain_details);

SELECT * 
FROM strain_details 
WHERE strain_id = (
    SELECT strain_id 
    FROM strains 
    WHERE vaccine_effectiveness = (
        SELECT MAX(vaccine_effectiveness) 
        FROM strains
    )
);

SELECT SUM(vaccine_effectiveness) AS total_vaccine_effectiveness
FROM strains
WHERE country = 'USA';

SELECT strain_id, COUNT(gender) AS total_gender_entries
FROM strain_details
GROUP BY strain_id;

SELECT strain_name
FROM strains
WHERE virus_type = 'A' AND country = 'USA';

SELECT strain_name
FROM strains
WHERE (country = 'Iran' OR country = 'USA') AND vaccine_effectiveness > 0.8;
